    "logging": {
      "coverage": "gaps",
      "gaps": [
        "No mention of structured logging for fraud check failures or Stripe errors",
        "No correlation ID / request ID for tracing a payment through fraud-check → Stripe → DB write",
        "No logging of circuit breaker state transitions (open/half-open/closed)",
        "No logging of DB connection pool utilization or wait times"
      ]
    },
